import subprocess
import shlex

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    command = input("Enter a command: ")

    # Whitelist validation - only allow specific safe commands
    allowed_commands = {'ls', 'pwd', 'echo', 'cat', 'date', 'whoami', 'hostname', 'head', 'tail', 'wc'}

    if not command.strip():
        return "No command entered"

    try:
        parts = shlex.split(command)
    except ValueError:
        return "Invalid command syntax"

    if not parts:
        return "No command entered"

    base_command = parts[0]

    if base_command not in allowed_commands:
        return f"Command '{base_command}' is not allowed. Allowed commands: {', '.join(sorted(allowed_commands))}"

    try:
        result = subprocess.run(
            parts,
            capture_output=True,
            text=True,
            timeout=5,
            check=False
        )

        if result.returncode != 0 and result.stderr:
            return result.stderr

        return result.stdout if result.stdout else f"Command '{base_command}' executed successfully"

    except subprocess.TimeoutExpired:
        return "Command timed out after 5 seconds"
    except PermissionError:
        return "Permission denied"
    except FileNotFoundError:
        return f"Command '{base_command}' not found"
    except Exception as e:
        return f"Error executing command: {str(e)}"

