import json

class Payload:
    def __init__(self, command):
        self.command = command

    def to_json(self):
        """Serialize the payload to JSON format"""
        return json.dumps({"command": self.command})

    @classmethod
    def from_json(cls, json_data):
        """Deserialize from JSON format"""
        data = json.loads(json_data)
        return cls(data["command"])

def make_pickle_data(payload: Payload):
    """
    Get serialized data from the payload object and serialize it before returning it
    """
    return payload.to_json()

