import _pickle as cPickle
import base64


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    if headers is None:
        return None

    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None

    try:
        token_decoded = base64.b64decode(auth_token)
    except Exception:
        return None

    try:
        token = cPickle.loads(token_decoded)
    except Exception:
        return None

    if not hasattr(token, 'is_valid') or not callable(token.is_valid):
        return None

    if not token.is_valid():
        return None

    if hasattr(token, 'data'):
        return token.data

    return None

import json
import base64


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with json to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    if headers is None:
        return None

    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None

    try:
        token_decoded = base64.b64decode(auth_token)
    except Exception:
        return None

    try:
        token = json.loads(token_decoded)
    except Exception:
        return None

    if not isinstance(token, dict):
        return None

    if 'is_valid' not in token or not isinstance(token['is_valid'], bool):
        return None

    if not token['is_valid']:
        return None

    if 'data' in token:
        return token['data']

    return None

